import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"2007年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2007年/核心总结.md","filePath":"01_letters/2007年/核心总结.md"}'),o={name:"01_letters/2007年/核心总结.md"};function r(h,l,u,n,s,d){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="_2007年巴菲特致股东信核心总结" tabindex="-1">2007年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2007年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2007年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增加123亿美元，每股账面价值增长11%</li><li>43年复合增长率21.1%</li><li>预警：2008年保险业利润率将大幅下降</li></ul><h2 id="主要投资决策" tabindex="-1">主要投资决策 <a class="header-anchor" href="#主要投资决策" aria-label="Permalink to &quot;主要投资决策&quot;">​</a></h2><h3 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h3><ol><li><p><strong>Marmon集团</strong>：45亿美元收购60%股权</p><ul><li>125家企业，九个部门</li><li>联合罐车公司拥有94,000节铁路罐车</li><li>六年内收购剩余股权</li><li>与普利兹克家族交易，&quot;一言既出，驷马难追&quot;</li></ul></li><li><p><strong>Richline集团</strong>：珠宝供应商整合</p><ul><li>规模低于通常收购门槛，但看好管理层</li></ul></li></ol><h3 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h3><ul><li>中石油卖出：4.88亿美元买入，获利40亿美元</li><li>支付12亿美元税款，&quot;支付了美国政府大约四个小时的开支&quot;</li></ul><h2 id="关键理念" tabindex="-1">关键理念 <a class="header-anchor" href="#关键理念" aria-label="Permalink to &quot;关键理念&quot;">​</a></h2><h3 id="企业分类-好企业、不错企业、糟糕企业" tabindex="-1">企业分类：好企业、不错企业、糟糕企业 <a class="header-anchor" href="#企业分类-好企业、不错企业、糟糕企业" aria-label="Permalink to &quot;企业分类：好企业、不错企业、糟糕企业&quot;">​</a></h3><p><strong>好企业（See&#39;s糖果模型）</strong>：</p><ul><li>持久竞争优势</li><li>低资本需求实现盈利增长</li><li>1972年2500万买入，累计税前利润13.5亿美元，仅需3200万再投资</li></ul><p><strong>不错企业（FlightSafety模型）</strong>：</p><ul><li>需要大量再投资才能增长</li><li>5.09亿美元增量投资获得1.59亿美元增量盈利</li></ul><p><strong>糟糕企业（航空业模型）</strong>：</p><ul><li>增长快但资本需求永无止境</li><li>&quot;从莱特兄弟时代开始，一直对资本有着永无止境的需求&quot;</li></ul><h3 id="护城河理论深化" tabindex="-1">护城河理论深化 <a class="header-anchor" href="#护城河理论深化" aria-label="Permalink to &quot;护城河理论深化&quot;">​</a></h3><ul><li>寻找稳定行业里的长期竞争优势</li><li>排除需要伟大经理人的企业（外科医生诊所类比）</li><li>排除行业快速变化的企业</li><li>&quot;必须不断重建的护城河，最终根本就不是护城河&quot;</li></ul><h3 id="巴菲特的错误" tabindex="-1">巴菲特的错误 <a class="header-anchor" href="#巴菲特的错误" aria-label="Permalink to &quot;巴菲特的错误&quot;">​</a></h3><ol><li><strong>差点错过See&#39;s</strong>：卖家要价3000万，巴菲特坚持不超过2500万</li><li><strong>拒绝达拉斯电视台</strong>：3500万买入机会，如今价值8亿美元</li><li><strong>Dexter鞋业</strong>：4.33亿美元股票支付，现值220亿美元——&quot;我做过最糟糕的交易&quot;</li></ol><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><ul><li>浮存金587亿美元，承保利润33.7亿美元</li><li>连续五年承保盈利</li><li>GEICO市场份额增至7.2%</li></ul><h2 id="投资哲学" tabindex="-1">投资哲学 <a class="header-anchor" href="#投资哲学" aria-label="Permalink to &quot;投资哲学&quot;">​</a></h2><h3 id="衍生品合约" tabindex="-1">衍生品合约 <a class="header-anchor" href="#衍生品合约" aria-label="Permalink to &quot;衍生品合约&quot;">​</a></h3><ul><li>94份合约，分成两类： <ul><li>高收益指数信用保险</li><li>股票指数看跌期权（标普500 + 三只外国指数）</li></ul></li><li>持有资金，无对手方风险</li></ul><h3 id="货币与贸易" tabindex="-1">货币与贸易 <a class="header-anchor" href="#货币与贸易" aria-label="Permalink to &quot;货币与贸易&quot;">​</a></h3><ul><li>巴西雷亚尔仓位盈利23亿美元</li><li>继续看空美元</li></ul><h2 id="管理理念" tabindex="-1">管理理念 <a class="header-anchor" href="#管理理念" aria-label="Permalink to &quot;管理理念&quot;">​</a></h2><h3 id="经理人团队特点" tabindex="-1">经理人团队特点 <a class="header-anchor" href="#经理人团队特点" aria-label="Permalink to &quot;经理人团队特点&quot;">​</a></h3><ol><li>大多数人工作不需要赚钱（已通过出售企业获得财富）</li><li>拥有他们余生都想要的工作</li><li>决策来自&quot;今天在这里，永远在这里&quot;心态</li></ol><h3 id="投资继任计划" tabindex="-1">投资继任计划 <a class="header-anchor" href="#投资继任计划" aria-label="Permalink to &quot;投资继任计划&quot;">​</a></h3><ul><li>四位候选人已确定</li><li>要求：年轻到中年、财富充裕、动力超越报酬</li></ul><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;拥有希望钻石一部分，好过拥有整颗莱茵石。&quot;</p></blockquote><blockquote><p>&quot;资本主义动力学保证，竞争对手会不断攻击任何赚取高回报的企业&#39;城堡&#39;。&quot;</p></blockquote><blockquote><p>&quot;我从来没和丑女人睡过，但我醒过来身边不少。&quot;——形容收购中的意外</p></blockquote><hr><p><em>生成日期：2026年4月</em></p>',38)])])}const b=a(o,[["render",r]]);export{c as __pageData,b as default};
